# Enable B2B Direct Connect with a specific partner tenant
# REQUIREMENT: BOTH tenants must configure inbound AND outbound direct connect

$partnerTenantId = "aaaabbbb-0000-1111-2222-333344445555"

# Step 1: Create the partner CTAS entry if it doesn't exist
try {
    Invoke-MgGraphRequest -Method GET \
        -Uri "https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners/$partnerTenantId"
} catch {
    Invoke-MgGraphRequest -Method POST \
        -Uri 'https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners' \
        -Body (@{ tenantId = $partnerTenantId } | ConvertTo-Json) \
        -ContentType 'application/json'
}

# Step 2: Configure B2B Direct Connect inbound and outbound
$dcConfig = @{
    b2bDirectConnectInbound = @{
        usersAndGroups = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
        }
        applications = @{
            accessType = 'allowed'
            targets    = @(
                @{ target = 'Office365'; targetType = 'application' }
            )
        }
    }
    b2bDirectConnectOutbound = @{
        usersAndGroups = @{
            accessType = 'allowed'
            targets    = @(@{ target = 'AllUsers'; targetType = 'user' })
        }
        applications = @{
            accessType = 'allowed'
            targets    = @(
                @{ target = 'Office365'; targetType = 'application' }
            )
        }
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners/$partnerTenantId" \
    -Body $dcConfig -ContentType 'application/json'
Write-Host 'B2B Direct Connect enabled. Ask partner tenant to configure their side too.'

# Apply Conditional Access policy for B2B Direct Connect sign-ins
# Target: external users accessing via direct connect (Teams shared channels)
$caBody = @{
    displayName = 'Require MFA for B2B Direct Connect'
    state = 'enabled'
    conditions = @{
        users = @{
            includeGuestsOrExternalUsers = @{
                guestOrExternalUserTypes = 'b2bDirectConnectUser'
                externalTenants = @{ membershipKind = 'all' }
            }
        }
        applications = @{
            includeApplications = @('All')
        }
        clientAppTypes = @('all')
    }
    grantControls = @{
        operator = 'OR'
        builtInControls = @('mfa')
    }
} | ConvertTo-Json -Depth 8

New-MgIdentityConditionalAccessPolicy -BodyParameter ($caBody | ConvertFrom-Json)
Write-Host 'CA policy created for B2B Direct Connect sign-ins'

# List all external members in a Teams Shared Channel
$teamId    = "ddddeeee-1111-2222-3333-444455556666"
$channelId = Get-TeamChannel -GroupId $teamId |
    Where-Object { $_.MembershipType -eq "Shared" -and $_.DisplayName -eq 'Partner Collaboration' } |
    Select-Object -ExpandProperty Id

# Get all channel members
$members = Get-TeamChannelUser -GroupId $teamId -ChannelId $channelId
$external = $members | Where-Object { $_.User -like '*#EXT#*' -or $_.User -like '*@fabrikam.com' }

$external | ForEach-Object {
    [pscustomobject]@{
        User = $_.User
        Role = $_.Role
    }
} | Format-Table

# Remove a specific external user from the channel
# Remove-TeamChannelUser -GroupId $teamId -ChannelId $channelId -User 'partner@fabrikam.com'

# Offboard a partner: remove all their external users from shared channels,
# then revoke the CTAS direct connect policy
$partnerDomain   = "fabrikam.com"
$partnerTenantId = "aaaabbbb-0000-1111-2222-333344445555"

# Step 1: remove external members from all shared channels in all teams
$teams = Get-Team
foreach ($team in $teams) {
    $sharedChannels = Get-TeamChannel -GroupId $team.GroupId |
        Where-Object { $_.MembershipType -eq 'Shared' }
    foreach ($ch in $sharedChannels) {
        $members = Get-TeamChannelUser -GroupId $team.GroupId -ChannelId $ch.Id
        $partnerMembers = $members | Where-Object { $_.User -like "*@$partnerDomain" }
        foreach ($m in $partnerMembers) {
            Remove-TeamChannelUser -GroupId $team.GroupId -ChannelId $ch.Id -User $m.User
            Write-Host "Removed $($m.User) from $($team.DisplayName) / $($ch.DisplayName)"
        }
    }
}

# Step 2: disable direct connect in CTAS
$dcBlock = @{
    b2bDirectConnectInbound = @{
        usersAndGroups = @{ accessType = 'blocked'; targets = @(@{ target = 'AllUsers'; targetType = 'user' }) }
        applications   = @{ accessType = 'blocked'; targets = @(@{ target = 'AllApplications'; targetType = 'application' }) }
    }
    b2bDirectConnectOutbound = @{
        usersAndGroups = @{ accessType = 'blocked'; targets = @(@{ target = 'AllUsers'; targetType = 'user' }) }
        applications   = @{ accessType = 'blocked'; targets = @(@{ target = 'AllApplications'; targetType = 'application' }) }
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method PATCH \
    -Uri "https://graph.microsoft.com/v1.0/policies/crossTenantAccessPolicy/partners/$partnerTenantId" \
    -Body $dcBlock -ContentType 'application/json'
Write-Host 'B2B Direct Connect revoked for partner tenant'
